// Decodes an encoded XML string.
private static void XmlDecode()
{
  // Setup
  string xml = "<text>Here & There</text>";
  // Encodes a string with XML escape values.
  string encoded = LJCNetCommon.XmlEncode(xml);

  // Decodes an encoded XML string.
  string text = LJCNetCommon.XmlDecode(encoded);
  // text = "Text"
}

using LJCNetCommon;

// Encodes a string with XML escape values.
private static void XmlEncode()
{
  // Setup
  string xml = "<text>Here & There</text>";

  // Encodes a string with XML escape values.
  string encoded = NetCommon.XmlEncode(xml);

  // Check the text.
  string text = NetCommon.XmlDecode(encoded);
  // text = "Text"
}

using LJCNetCommon;

public class Person
{
  public long Id { get; set; }
  public string Name { get; set; }
  public bool PrincipleFlag { get; set; }
}

// Deserialize an XML message file to an object.
private static void XmlDeserialize()
{
  // Setup
  var person = new Person()
  {
    Id = 1,
    Name = "Text",
    PrincipleFlag = true
  };
  string file = "Text.xml";
  LJCNetCommon.XmlSerialize(person.GetType(), person, null, file);

  // Deserialize an XML message file to an object.
  Person newPerson;
  newPerson = LJCNetCommon.XmlDeserialize(typeof(Person), file) as Person;
}

using LJCNetCommon;

